mapper.select:
SELECT LINK_SEQ, NEWS_DAT_SEQ, LINK_NM, LINK_URL_ADR, CRET_ID, AMD_ID, CRET_DT, AMD_DT
FROM NMCP_NEWS_DATA_LINK_DTL

    AND NEWS_DAT_SEQ = #{newsDatSeq}

SELECT NEWS_DAT_SEQ, NEWS_DAT_SUBJECT, STAT_VAL, NEWS_DAT_IMG, IMG_DESC, NEWS_DAT_SBST, NEWS_DAT_HIT_CNT, LINK_URL_ADR, NOTI_YN, CRET_ID, AMD_ID, CRET_DT, AMD_DT, LINK_TARGET, NEWS_LINE_SBST, PRE_SEQ, PRE_SUBJECT, PRE_DT, NEXT_SEQ, NEXT_SUBJECT, NEXT_DT, UP_DT FROM ( SELECT NEWS_DAT_SEQ, NEWS_DAT_SUBJECT, STAT_VAL, NEWS_DAT_IMG, IMG_DESC, NEWS_DAT_SBST, NEWS_DAT_HIT_CNT, LINK_URL_ADR, NOTI_YN, CRET_ID, AMD_ID, CRET_DT, AMD_DT, LINK_TARGET, NEWS_LINE_SBST, LEAD(NEWS_DAT_SEQ, 1) OVER (ORDER BY NVL(UP_DT, CRET_DT) DESC, NEWS_DAT_SEQ DESC) AS PRE_SEQ, lead(NEWS_DAT_SUBJECT,1,'이전글이 없습니다.') over (ORDER BY NVL(UP_DT, CRET_DT) DESC, NEWS_DAT_SEQ DESC) PRE_SUBJECT, lead(CRET_DT,1,'') over (order by CRET_DT DESC) PRE_DT, lag(NEWS_DAT_SEQ, 1) OVER (ORDER BY NVL(UP_DT, CRET_DT) DESC, NEWS_DAT_SEQ DESC) AS NEXT_SEQ, lag(NEWS_DAT_SUBJECT,1,'다음글이 없습니다.') over (ORDER BY NVL(UP_DT, CRET_DT) DESC, NEWS_DAT_SEQ DESC) NEXT_SUBJECT, lag(CRET_DT,1,'') over (order by CRET_DT DESC) NEXT_DT, UP_DT FROM NMCP_NEWS_DATA_BAS WHERE STAT_VAL = 'Y' AND ( (ST_DT IS NOT NULL AND ED_DT IS NOT NULL AND ST_DT <= SYSDATE AND ED_DT >= TRUNC(SYSDATE)) OR (ST_DT IS NULL OR ED_DT IS NULL) ) )
AND NEWS_DAT_SEQ = #{newsDatSeq}
ORDER BY CASE WHEN UP_DT IS NOT NULL THEN UP_DT ELSE CRET_DT END DESC, NEWS_DAT_SEQ DESC
